export const getImageSizeFromUrl = async (
  url: string
): Promise<{ width: number; height: number }> => {
  const img = new Image();
  img.src = url;

  return new Promise((resolve) => {
    img.onload = () => {
      const { width, height } = img;
      resolve({
        width,
        height,
      });
    };
  });
};
